import{_ as e,o as a,c as t,ag as _}from"./chunks/framework.DPqexil4.js";const m=JSON.parse('{"title":"第二十一章 十战九败","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第二十一章-十战九败.md","filePath":"永恒道途/正文/第一卷-山门有路/第二十一章-十战九败.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第二十一章-十战九败.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第二十一章-十战九败" tabindex="-1">第二十一章 十战九败 <a class="header-anchor" href="#第二十一章-十战九败" aria-label="Permalink to &quot;第二十一章 十战九败&quot;">​</a></h1><p>入剑峰第八个月，陈玄踏入炼气九层。</p><p>从八层到九层，他用了近半年。</p><p>这半年里，掌天瓶共凝出六滴绿液。两滴催熟养脉灵药，修补瀑布练剑留下的暗伤；一滴催熟聚气花，分成三次药浴；剩下三滴仍封在瓶中，没有为了赶上会武全部耗尽。</p><p>李清风为他开了剑峰聚灵阵，也亲自调整过《吐纳诀》的行气细节。即便如此，四属性灵根仍像四条宽窄不同的河，每次破境都要先让四股灵力达到平衡。</p><p>最后那道瓶颈，陈玄足足磨了二十七日。</p><p>突破当夜，他没有看见所谓“灵力液化”。炼气九层仍是气态灵力，只是丹田气旋由虚转实，每一缕灵力都比八层更加凝练。真正开辟气海、使灵力大规模液化，要等到筑基。</p><p>陈玄收功后，把这点变化详细记进修炼册。</p><p>境界不能只靠一个名称判断。身体发生了什么，能承受几次剑气，恢复速度快了多少，这些才是斗法时真正有用的东西。</p><p>第二日，李清风以枯枝试了他三十招。</p><p>陈玄逼退师父两步，自己被点中七次。</p><p>“炼气九层，只让你灵力更厚。”李清风道，“若因此觉得昨日的错误今日便不是错误，境界越高，死得越快。”</p><p>“弟子记住了。”</p><p>“七宗名额选拔在三日后。剑峰只推你一人，输了便回来继续练。”</p><p>青云宗共有二十七名年轻弟子参加选拔，争五个名额。</p><p>陈玄第一场对阵灵兽峰弟子，第二场遇上符峰的炼气九层，第三场则对上内门老弟子张远。三战没有一场轻松。</p><p>符峰弟子以四象符锁住整座擂台，陈玄直到护身符被轰碎才找到阵眼；张远的双刀一长一短，出招从不按相同节奏，陈玄以青莲第一瓣逼位三次，都没能让他走向预定位置。</p><p>最后一击，陈玄故意放弃逼位，把第一瓣斩向无人处。</p><p>张远以为他失手，短刀抢入中门，正好撞上早已收回的第二瓣。青锋剑停在心口前时，张远盯着那片还未散尽的青芒看了许久。</p><p>“你第一剑是故意斩空？”</p><p>“师父说，剑不一定每一招都要赚到东西。”</p><p>张远收刀苦笑：“李长老这句话，今日拿我作了注解。”</p><p>陈玄由此拿到五个名额中的第四位。</p><p>另外四人分别是叶承、秦岚、张远与李明月。苏婉错过了宗内选拔，她此前一直在寒潭闭关，准备冲击炼气大圆满。出关后，宗门让她以候补与观战弟子身份随行。</p><p>会武出发前夜，李清风没有再让陈玄练剑。</p><p>师徒二人坐在古松下吃面。风吹得碗中热气不断向南偏，李清风用筷子压住一片差点飞走的菜叶，只交代两件事。</p><p>“第一，七宗战台有护阵，不代表没人会死。裁判出手也要时间。”</p><p>“第二，血魔子已经筑基。你可看，可记，若抽中他，先想如何活，再想如何胜。”</p><p>陈玄问：“师父觉得我必败？”</p><p>“以你现在的修为，正面交手，十战九败。”</p><p>“还有一战？”</p><p>李清风抬眼看他：“那一战不是让你拿来做梦，是提醒你世上没有绝对。但在真正找到那一线之前，按九败准备。”</p><p>陈玄记下了。</p><p>三日后，青云宗飞舟抵达断岳古城。</p><p>古城位于青云州北境，城墙以黑铁岩砌成，远望像一条横卧平原的山脉。七宗会武期间，城门上悬着七面长旗，各宗弟子、散修与商队沿四方官道汇聚而来，尚未进城便能感受到一股股不同灵压。</p><p>这是陈玄第一次真正离开青云宗势力腹地。</p><p>城中售卖的不再只有低阶丹药与一阶妖材。街边店铺里摆着筑基修士使用的灵器，拍卖楼门前拴着两头二阶风驼，连路边替人鉴药的老者都有炼气后期修为。</p><p>王胖子没有参战，却自费跟着商队来了。</p><p>“七宗会武三年一次，三十五名弟子的输赢能养活半条赌坊街。”他一进城便两眼放光，“我不来，岂不是对不起这些年攒的灵石？”</p><p>陈玄看向他腰间三个钱袋：“你带了多少？”</p><p>“不多。”</p><p>“多少？”</p><p>“生意人的本钱，不能随便透露。”</p><p>陈玄决定不再问。</p><p>会场设在古城中央的断岳战台。</p><p>战台由整块白色岩石铺成，四周立着三十六根阵柱。七宗席位沿北侧高台依次排开，散修与世家观众则坐在外围石阶上。数万人同时交谈，声浪层层叠叠，像潮水拍击城墙。</p><p>高台上，青云、玄岳、天河、赤炎、灵兽、太玄与血魔七面宗旗依次展开。</p><p>血魔宗旗升起时，青云席位明显安静了些。</p><p>黑风山据点的事只过去不到一年。宗门高层没有公开全部细节，参战弟子却都知道双方边境摩擦正在加剧。</p><p>血魔宗一行坐在最西侧。五名弟子皆穿暗红长袍，为首青年披着黑色外氅，脸色苍白，双手干净修长，看上去甚至有几分文弱。</p><p>可当他的目光扫过战台时，陈玄胸前旧伤忽然传来极轻的刺痛。</p><p>不是伤口复发。</p><p>是同源血煞引起的残余反应。</p><p>血魔子。</p><p>对方似有所觉，目光越过两宗席位，准确落在陈玄身上。</p><p>陈玄没有避开，也没有挑衅，只把那张脸与气息牢牢记住。</p><p>“他认识你？”站在旁边的苏婉问。</p><p>“薛七死前写给他的信，在我手里。”</p><p>苏婉知道黑风山一案，闻言便明白过来：“会武中遇上，他不会留手。”</p><p>“我知道。”</p><p>“筑基与炼气不是两个小层次的差别。”她声音很轻，“真到必须认输时，不要等裁判替你决定。”</p><p>陈玄看向她：“你也觉得我十战九败？”</p><p>苏婉微微一怔：“谁与你说过同样的话？”</p><p>“我师父。”</p><p>“李师叔说得对。”她顿了顿，“剩下一战，也不是让你拿命赌。”</p><p>同样的意思，从两个人口中说出来，一个像石，一个像水。</p><p>陈玄点头：“我记住了。”</p><p>会武钟声响起，第一轮抽签开始。</p><p>七宗各出五人，共三十五人。一人轮空，其余弟子两两对战。竹签展开后，陈玄的对手是玄岳宗石鸣。</p><p>炼气九层，土系体修。</p><p>“第一擂，青云宗陈玄，对玄岳宗石鸣！”</p><p>石鸣跃上战台时，白岩发出一声闷响。他比孙铁更高，也更沉，双臂各套一只玄铁护臂。护臂没有锋刃，表面却刻着增重阵纹，每一次握拳都有土黄色灵光沿纹路流动。</p><p>“青云宗第三？”石鸣问。</p><p>“内门选拔第三。”</p><p>“都一样。”石鸣咧嘴，“听说你擅长等别人露破绽。我不急，你慢慢等。”</p><p>陈玄拔出青锋剑。</p><p>对手看过他的情报。</p><p>这正是七宗会武与宗内大比的不同。能走到这里的人不会轻易把弱点摆出来，也不会因他出身药园便先入为主地轻敌。</p><p>裁判落手。</p><p>石鸣没有狂奔抢攻，只一步步向前。每一步落下，土灵力便在脚下结成一层浅黄地纹。走到战台中央时，地纹已经连成半圆，将陈玄活动范围缓慢压缩。</p><p>他在逼陈玄先出手。</p><p>陈玄如他所愿，一剑刺出。</p><p>青锋起直取右肩，石鸣抬臂挡住。剑刃斩在玄铁护臂上，火星一闪，陈玄立刻借反震退开。</p><p>第二剑斩左膝。</p><p>石鸣仍只守不攻。</p><p>第三剑、第四剑，青芒分别落在肋侧与腕间，都没能破开土系护体。</p><p>看台开始有人议论。</p><p>“陈玄的剑破不了石鸣。”</p><p>“玄岳宗早把他的路数研究透了。只要不乱攻，他那些算计便没处用。”</p><p>石鸣听见声音，神情没有一丝松动：“还有什么，都使出来。”</p><p>陈玄第五次起剑。</p><p>这一剑却斩向石鸣右侧空地。</p><p>青芒落在白岩上，只留下一道浅痕。石鸣眼中闪过一丝疑惑，脚步仍稳稳前压。</p><p>第六剑又斩空。</p><p>第七剑仍然没有碰到人。</p><p>三道剑痕分布在石鸣右侧，看不出任何联系。玄岳宗席位已经有人发笑，王胖子却收起扇子，盯住了石鸣脚下。</p><p>第八剑，陈玄终于刺向正面。</p><p>石鸣抬起双臂，准备以护臂夹住剑身。陈玄却在剑锋触铁前收力，左脚向外侧踏出半步。</p><p>石鸣本能随之调整重心。</p><p>这一脚，恰好踩在前三道剑痕之间。</p><p>陈玄先前斩出的不是杀招，而是切断地纹的三条细线。石鸣脚下土灵力原本连成一体，此刻重心落下，三条裂痕同时崩开，护体灵光出现一瞬不稳。</p><p>陈玄的第九剑已经到了。</p><p>青莲第一瓣不攻身体，只压住石鸣向左回稳的脚步；第二瓣斩在右侧护臂与肩甲连接处；第三瓣没有立刻出剑，而是停在剑锋之内。</p><p>石鸣低吼一声，索性放弃防守，以左拳正面轰向陈玄胸口。</p><p>他要以伤换伤。</p><p>陈玄没有与体修换拳。第二瓣命中后立刻收剑，折云步向后斜退。拳风擦过胸前，撕开衣襟，却没有真正落下。</p><p>石鸣一拳落空，右侧护体又被切开，第一次主动追了上来。</p><p>他终于从“绝不急攻”的计划里走出了一步。</p><p>接下来的二十息，攻守彻底翻转。</p><p>石鸣拳重，每一次落下都让战台震动。陈玄不再一味后退，而是以先前留下的剑痕为界，引着对手不断跨过断裂地纹。石鸣的土灵力无法连成完整地势，护体强弱随脚步不断变化。</p><p>第三十七息，他右肩连接处第二次出现空隙。</p><p>陈玄一直藏在剑锋内的第三瓣终于斩出。</p><p>剑气穿过护体空隙，停在石鸣咽喉前一寸。</p><p>石鸣的拳也停在陈玄胸前两寸。</p><p>两人都没有再进。</p><p>裁判看清先后，高声道：“陈玄胜！”</p><p>石鸣慢慢放下拳，低头看了看脚下三道最初被他忽略的剑痕。</p><p>“你前七剑，一剑都没想伤我？”</p><p>“想让你走到这里。”</p><p>石鸣沉默片刻，抱拳：“我输得不冤。下一次，我会连地面一起防。”</p><p>陈玄还礼：“下一次，我也不会再用同样的剑。”</p><p>走下战台时，他右臂微微发酸，灵力却还剩六成。</p><p>李清风教他的那句“剑不必每一招都赚”，第一次在七宗台上真正换来胜局。</p><p>可下一场比试，让整个会场迅速安静下来。</p><p>“第二擂，血魔宗血魔子，对太玄宗徐衡。”</p><p>徐衡是炼气九层巅峰，符法兼修。钟声落下，他没有试探，七张符箓同时飞出，火、雷、金三色灵光交织成网。</p><p>血魔子站在原地，直到符网临身才抬起右手。</p><p>血雾从袖中涌出，不与符光正面碰撞，而是贴着灵力缝隙向前蔓延。火符灼掉一层血雾，更多血丝却顺着爆开的气流绕到徐衡身后。</p><p>徐衡立刻祭出护身镜。</p><p>镜光刚起，脚下影子中忽然伸出一只血色手掌，扣住他的脚踝。</p><p>只这一瞬迟滞，血魔子已经越过符网。</p><p>血刀没有斩向咽喉，而是落在护身镜中央。第一刀让镜面出现裂纹，第二刀沿同一点落下，第三刀才将护镜与徐衡一同劈出数丈。</p><p>徐衡落地后尚未出界，血煞却已经钻入胸口。</p><p>他痛得蜷缩起来，皮肤下浮出一道道暗红细线。</p><p>“认输！”太玄宗长老站起身厉喝。</p><p>裁判也在同一刻挡到两人之间。</p><p>血魔子没有违抗，收刀退后。可他下刀的位置、血煞的分量，恰好足以让徐衡重伤，又不会当场毙命。</p><p>这份精确比失控杀人更让人心冷。</p><p>“三招。”叶承低声道。</p><p>陈玄没有数招，只在记血雾如何绕过符网，血色手掌又从何处出现。</p><p>血魔子走下战台，没有接受同门道贺，径直停在青云宗席位前。</p><p>“薛七是你杀的？”</p><p>高台周围顿时安静。</p><p>陈玄道：“是。”</p><p>“他蠢，死了不值得可惜。”血魔子笑意很淡，“可他身上有一封给我的信。”</p><p>“信在青云宗刑律峰。”</p><p>“没关系。”血魔子看着陈玄，猩红眼底没有愤怒，只有一种近乎冷静的兴趣，“等你死后，我会自己去取。”</p><p>陈玄握剑的手没有收紧：“想取，先赢。”</p><p>血魔子笑了一声，转身离开。</p><p>第一轮结束时，青云宗五人晋级四人。张远败给赤炎宗弟子，伤势不重；叶承、秦岚与李明月皆顺利取胜。</p><p>夜里，陈玄在临时驻地复盘血魔子那三刀。</p><p>血雾不是凭空越过符网，而是借火符爆裂时的灵气回流贴地绕行；影中血手也不是空间术法，地面在开战前便被一滴血种污染。</p><p>他把这些判断写在纸上，又逐一标注“不确定”。看见是一回事，能否破解是另一回事。</p><p>苏婉送来一瓶清煞丹，放在桌上：“丹峰长老让我给你。血魔子的血煞比薛七强十倍，若中招，回脉草未必来得及。”</p><p>“多谢。”</p><p>“明日第二轮抽签。”她道，“希望不是你。”</p><p>“若是呢？”</p><p>苏婉看向桌上那张写满推演的纸：“那便先把你看见的东西都用上，再决定剩下一战在哪里。”</p><p>第二日清晨，战台前重新抽签。</p><p>执事展开第三枚竹签时，声音停了一瞬。</p><p>“青云宗，陈玄。”</p><p>另一枚签随之翻开。</p><p>“对血魔宗，血魔子。”</p><p>喧声像被一只无形大手按灭。</p><p>陈玄抬起头。</p><p>战台另一侧，血魔子也正看着他，唇边浮起一丝早有所料的笑。</p><p>李清风说，十战九败。</p><p>剩下一战，不在运气里。</p><p>在他昨夜写下的每一个“不确定”中。</p><p>（第二十一章完）</p>',170)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
